import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Button,
  Grid,
  Card,
  CardContent,
  useTheme,
  Tabs,
  Tab,
  Avatar,
  Divider,
  Paper,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
} from '@mui/material';
import {
  LocalHospital,
  People,
  AccessTime,
  MedicalServices,
  CalendarToday,
  Assignment,
  History,
  Star,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const features = [
  {
    icon: <LocalHospital fontSize="large" />,
    title: 'Modern Facilities',
    description: 'State-of-the-art medical equipment and comfortable patient rooms.',
  },
  {
    icon: <People fontSize="large" />,
    title: 'Expert Doctors',
    description: 'Highly qualified and experienced medical professionals.',
  },
  {
    icon: <AccessTime fontSize="large" />,
    title: '24/7 Service',
    description: 'Round-the-clock emergency and medical services.',
  },
  {
    icon: <MedicalServices fontSize="large" />,
    title: 'Comprehensive Care',
    description: 'Wide range of medical specialties and treatment options.',
  },
];

const Home = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState(0);
  const [doctors, setDoctors] = useState([]);
  const [userAppointments, setUserAppointments] = useState([]);
  const [prescriptions, setPrescriptions] = useState([]);

  useEffect(() => {
    // Fetch doctors list
    const fetchDoctors = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/doctors');
        setDoctors(response.data);
      } catch (error) {
        console.error('Error fetching doctors:', error);
      }
    };

    // Fetch user-specific data if logged in
    const fetchUserData = async () => {
      if (user) {
        try {
          const [appointmentsRes, prescriptionsRes] = await Promise.all([
            axios.get(`http://localhost:5000/api/appointments/user/${user.id}`),
            axios.get(`http://localhost:5000/api/prescriptions/user/${user.id}`)
          ]);
          setUserAppointments(appointmentsRes.data);
          setPrescriptions(prescriptionsRes.data);
        } catch (error) {
          console.error('Error fetching user data:', error);
        }
      }
    };

    fetchDoctors();
    fetchUserData();
  }, [user]);

  const handleTabChange = (event, newValue) => {
    setActiveTab(newValue);
  };

  const handleBookAppointment = () => {
    if (!user) {
      navigate('/login');
    } else {
      navigate('/appointments/book');
    }
  };

  const renderUserDashboard = () => (
    <Box sx={{ mt: 4 }}>
      <Paper sx={{ p: 3, mb: 3 }}>
        <Typography variant="h5" gutterBottom sx={{ fontWeight: 600 }}>
          Your Dashboard
        </Typography>
        <Grid container spacing={3}>
          <Grid item xs={12} md={4}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <CalendarToday color="primary" sx={{ mr: 1 }} />
                  <Typography variant="h6">Upcoming Appointments</Typography>
                </Box>
                <Typography variant="h4" color="primary">
                  {userAppointments.filter(apt => new Date(apt.date) > new Date()).length}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={4}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Assignment color="secondary" sx={{ mr: 1 }} />
                  <Typography variant="h6">Prescriptions</Typography>
                </Box>
                <Typography variant="h4" color="secondary">
                  {prescriptions.length}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={4}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <History color="info" sx={{ mr: 1 }} />
                  <Typography variant="h6">Past Appointments</Typography>
                </Box>
                <Typography variant="h4" color="info.main">
                  {userAppointments.filter(apt => new Date(apt.date) < new Date()).length}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      </Paper>
      <Button
        variant="contained"
        color="primary"
        size="large"
        onClick={handleBookAppointment}
        sx={{ mb: 4 }}
      >
        Book New Appointment
      </Button>
    </Box>
  );

  const renderHospitalInfo = () => (
    <Box>
      <Tabs value={activeTab} onChange={handleTabChange} centered sx={{ mb: 4 }}>
        <Tab label="About Us" />
        <Tab label="Our Doctors" />
        <Tab label="Services" />
        <Tab label="Management" />
      </Tabs>

      {activeTab === 0 && (
        <Container maxWidth="md">
          <Typography variant="h4" gutterBottom sx={{ fontWeight: 700 }}>
            About Lumbini Nepal Hospital
          </Typography>
          <Typography paragraph>
            Established in 2010, Lumbini Nepal Hospital has been at the forefront of medical excellence
            and patient care in Nepal. Our state-of-the-art facility spans over 50,000 square feet and
            houses the latest medical technology and equipment.
          </Typography>
          <Typography paragraph>
            We are committed to providing comprehensive healthcare services with compassion and
            excellence. Our team of experienced medical professionals works tirelessly to ensure the
            highest standards of patient care and safety.
          </Typography>
          <Box sx={{ my: 4 }}>
            <Grid container spacing={3}>
              <Grid item xs={12} sm={6}>
                <Paper sx={{ p: 3, height: '100%' }}>
                  <Typography variant="h6" gutterBottom>
                    Our Mission
                  </Typography>
                  <Typography>
                    To provide accessible, high-quality healthcare services to all members of our
                    community while advancing medical knowledge through research and education.
                  </Typography>
                </Paper>
              </Grid>
              <Grid item xs={12} sm={6}>
                <Paper sx={{ p: 3, height: '100%' }}>
                  <Typography variant="h6" gutterBottom>
                    Our Vision
                  </Typography>
                  <Typography>
                    To be the leading healthcare institution in Nepal, recognized for excellence in
                    patient care, medical education, and research.
                  </Typography>
                </Paper>
              </Grid>
            </Grid>
          </Box>
        </Container>
      )}

      {activeTab === 1 && (
        <Container maxWidth="lg">
          <Typography variant="h4" gutterBottom sx={{ fontWeight: 700 }}>
            Our Expert Doctors
          </Typography>
          <Grid container spacing={3}>
            {doctors.map((doctor) => (
              <Grid item xs={12} sm={6} md={4} key={doctor.id}>
                <Card>
                  <CardContent>
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                      <Avatar
                        src={doctor.image || ''}
                        sx={{ width: 64, height: 64, mr: 2 }}
                      />
                      <Box>
                        <Typography variant="h6">{doctor.name}</Typography>
                        <Typography color="textSecondary">{doctor.specialization}</Typography>
                      </Box>
                    </Box>
                    <Typography variant="body2" paragraph>
                      {doctor.description}
                    </Typography>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <Star sx={{ color: theme.palette.warning.main, mr: 1 }} />
                      <Typography variant="body2">
                        {doctor.rating} ({doctor.reviewCount} reviews)
                      </Typography>
                    </Box>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Container>
      )}

      {activeTab === 2 && (
        <Container maxWidth="md">
          <Typography variant="h4" gutterBottom sx={{ fontWeight: 700 }}>
            Our Services
          </Typography>
          <Grid container spacing={4}>
            {features.map((feature, index) => (
              <Grid item xs={12} sm={6} key={index}>
                <Card sx={{ height: '100%' }}>
                  <CardContent>
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                      <Box sx={{ color: theme.palette.primary.main, mr: 2 }}>
                        {feature.icon}
                      </Box>
                      <Typography variant="h6">{feature.title}</Typography>
                    </Box>
                    <Typography variant="body2" color="text.secondary">
                      {feature.description}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Container>
      )}

      {activeTab === 3 && (
        <Container maxWidth="md">
          <Typography variant="h4" gutterBottom sx={{ fontWeight: 700 }}>
            Hospital Management
          </Typography>
          <Paper sx={{ p: 3, mb: 4 }}>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
              <Avatar
                src="/images/director.jpg"
                sx={{ width: 120, height: 120, mr: 3 }}
              />
              <Box>
                <Typography variant="h5" gutterBottom>
                  Dr. Rajesh Kumar
                </Typography>
                <Typography variant="subtitle1" color="primary" gutterBottom>
                  Hospital Director
                </Typography>
                <Typography variant="body2">
                  With over 25 years of experience in healthcare management, Dr. Kumar leads our
                  institution with a vision for excellence and innovation in healthcare delivery.
                </Typography>
              </Box>
            </Box>
          </Paper>
          <Typography variant="h5" gutterBottom sx={{ mt: 4 }}>
            Management Team
          </Typography>
          <List>
            {[
              {
                name: 'Dr. Sarah Johnson',
                role: 'Medical Director',
                description: 'Oversees all medical operations and quality of care',
              },
              {
                name: 'Mr. David Chen',
                role: 'Administrative Director',
                description: 'Manages hospital operations and administrative functions',
              },
              {
                name: 'Dr. Maria Garcia',
                role: 'Chief of Medical Staff',
                description: 'Coordinates between management and medical staff',
              },
            ].map((member, index) => (
              <React.Fragment key={index}>
                <ListItem alignItems="flex-start">
                  <ListItemAvatar>
                    <Avatar>{member.name[0]}</Avatar>
                  </ListItemAvatar>
                  <ListItemText
                    primary={member.name}
                    secondary={
                      <>
                        <Typography component="span" variant="subtitle2" color="primary">
                          {member.role}
                        </Typography>
                        <br />
                        {member.description}
                      </>
                    }
                  />
                </ListItem>
                {index < 2 && <Divider variant="inset" component="li" />}
              </React.Fragment>
            ))}
          </List>
        </Container>
      )}
    </Box>
  );

  return (
    <Box>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: theme.palette.primary.main,
          color: 'white',
          py: 8,
          mb: 6,
          borderRadius: { xs: 0, md: '0 0 2rem 2rem' },
          boxShadow: 3,
        }}
      >
        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Typography 
                variant="h2" 
                gutterBottom
                sx={{
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  fontWeight: 700,
                  lineHeight: 1.2,
                }}
              >
                Welcome to Lumbini Nepal Hospital
              </Typography>
              <Typography 
                variant="h5" 
                sx={{ 
                  mb: 4,
                  opacity: 0.9,
                  fontSize: { xs: '1.2rem', md: '1.5rem' },
                }}
              >
                Providing quality healthcare services with compassion and excellence
              </Typography>
              <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                <Button
                  variant="contained"
                  color="secondary"
                  size="large"
                  onClick={handleBookAppointment}
                  sx={{
                    py: 1.5,
                    px: 4,
                    fontSize: '1.1rem',
                    fontWeight: 600,
                    '&:hover': {
                      transform: 'translateY(-2px)',
                      boxShadow: 4,
                    },
                    transition: 'all 0.2s',
                  }}
                >
                  Book Appointment
                </Button>
              </Box>
            </Grid>
            <Grid 
              item 
              xs={12} 
              md={6}
              sx={{
                display: { xs: 'none', md: 'block' }
              }}
            >
              <Box
                sx={{
                  position: 'relative',
                  '&::before': {
                    content: '""',
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    backgroundColor: theme.palette.primary.dark,
                    opacity: 0.1,
                    borderRadius: 2,
                  }
                }}
              >
                <Box
                  component="img"
                  src="/images/hospital-hero.jpg"
                  alt="Hospital"
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = 'https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?ixlib=rb-4.0.3';
                  }}
                  sx={{
                    width: '100%',
                    height: '400px',
                    borderRadius: 2,
                    boxShadow: 3,
                    objectFit: 'cover',
                  }}
                />
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* Main Content */}
      <Container maxWidth="lg" sx={{ mb: 8 }}>
        {user ? renderUserDashboard() : null}
        {renderHospitalInfo()}
      </Container>
    </Box>
  );
};

export default Home;
